// core/tree/engine/TreeLazy.ts

import type  { TreeNode } from '../models/TreeNode';
import { createTreeEvent, type PrimeTreeEvent } from './TreeEvents';

/**
 * Determines whether a node should be treated as lazy.
 */
export function isLazyNode(node: TreeNode): boolean {
  return node.leaf === false && node.children === undefined;
}

/**
 * Creates a lazy-load expand event.
 * Mirrors PrimeReact onExpand behavior.
 */
export function createLazyExpandEvent(
  node: TreeNode,
  originalEvent?: any
): PrimeTreeEvent<TreeNode> {
  return createTreeEvent(node, originalEvent);
}
